              backgroundColor: 'white',
              padding: '25px',
              borderRadius: '12px',
              boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
            }}>
              <div style={{ fontSize: '14px', color: '#666', marginBottom: '8px' }}>가장 활발한 시간</div>
              <div style={{ fontSize: '36px', fontWeight: 'bold', color: '#4ECDC4' }}>07:00-08:00</div>
              <div style={{ fontSize: '12px', color: '#999', marginTop: '8px' }}>오전 시간대</div>
            </div>

