        </div>
      )}

      {/* 카테고리별 분포 */}
      {activeView === 'category' && (
        <div style={{
          backgroundColor: 'white',
          padding: '30px',
          borderRadius: '12px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
        }}>
          <h3 style={{ marginTop: 0 }}>📁 이메일 카테고리 분포</h3>
          <ResponsiveContainer width="100%" height={400}>
            <PieChart>
              <Pie
                data={categoryData}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                outerRadius={120}
                fill="#8884d8"
                dataKey="value"
              >
                {categoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div style={{ marginTop: '30px' }}>
            {categoryData.map((cat, idx) => (
              <div key={idx} style={{
                display: 'flex',
                alignItems: 'center',
                marginBottom: '10px'
              }}>
                <div style={{
                  width: '20px',
                  height: '20px',
                  backgroundColor: cat.color,
                  borderRadius: '4px',
                  marginRight: '10px'
                }}></div>
                <span>{cat.name}: {cat.value}개</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* 주간 시간 배분 */}
      {activeView === 'weekly' && (
        <div style={{
          backgroundColor: 'white',
          padding: '30px',
          borderRadius: '12px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
        }}>
          <h3 style={{ marginTop: 0 }}>📅 주간 예상 시간 배분</h3>
          <p style={{ color: '#666', fontSize: '14px', marginBottom: '20px' }}>
            일주일 총 168시간의 활동 추정치입니다.
          </p>
          <ResponsiveContainer width="100%" height={400}>
            <BarChart data={weeklyTimeEstimate} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis type="number" label={{ value: '시간', position: 'insideBottom', offset: -5 }} />
              <YAxis type="category" dataKey="activity" width={100} />
              <Tooltip />
              <Legend />
              <Bar dataKey="hours" name="시간" fill="#667eea">
                {weeklyTimeEstimate.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
          <div style={{ marginTop: '30px' }}>
            <h4>시간 배분 상세</h4>
            {weeklyTimeEstimate.map((item, idx) => (
              <div key={idx} style={{
                display: 'flex',
                justifyContent: 'space-between',
                padding: '12px',
                borderBottom: '1px solid #f0f0f0'
              }}>
                <span style={{ display: 'flex', alignItems: 'center' }}>
                  <div style={{
                    width: '12px',
                    height: '12px',
                    backgroundColor: COLORS[idx],
                    borderRadius: '2px',
                    marginRight: '10px'
                  }}></div>
                  {item.activity}
                </span>
                <span style={{ fontWeight: 'bold' }}>
                  {item.hours}시간 ({((item.hours / 168) * 100).toFixed(1)}%)
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* 푸터 */}
      <footer style={{
        marginTop: '40px',
        padding: '20px',
        textAlign: 'center',
        color: '#999',
        fontSize: '14px'
      }}>
        <p>📊 Gmail 활동 데이터를 기반으로 생성된 시각화입니다.</p>
        <p>더 정확한 분석을 위해 Google Calendar 일정을 추가하면 좋습니다.</p>
      </footer>
    </div>
  );
};

export default WeeklyTimeTracker;
